SET NAMES utf8mb4;

UPDATE songs SET artist_bio='Laufey Lín Benediktsdóttir, known mononymously as Laufey, is an Icelandic singer-songwriter and multi-instrumentalist. Known for her dreamy blend of jazz, pop, and classical influences, she has gained massive popularity among Gen Z for making timeless music feel modern and accessible.' WHERE artist LIKE '%Laufey%';

UPDATE songs SET artist_bio='Bruno Peter Gene Marschall, known as Bruno Mars, is an American singer, songwriter, and record producer. Known for his wide vocal range and stage performances, he has won multiple Grammy Awards.' WHERE artist LIKE '%Bruno%';

UPDATE songs SET artist_bio='HONNE is the British electronic music duo of Andy Clutterbuck and James Hatcher. Their name derives from the Japanese words honne and tatemae, referring to the true feeling and the public face.' WHERE artist LIKE '%HONNE%';

UPDATE songs SET artist_bio='Stefani Joanne Angelina Germanotta, known as Lady Gaga, is an American singer, songwriter, and actress. Renowned for her versatility, she has sold over 170 million records worldwide.' WHERE artist LIKE '%Lady Gaga%';
